13	const countLiveNeighbors = (cells: Cell[]): Map<string, number> => {
14	  const counts = new Map<string, number>();
15	  for (const [x, y] of cells) {
16	    for (const [nx, ny] of neighborPositions(x, y)) {
17	      const k = cellKey(nx, ny);
18	      counts.set(k, (counts.get(k) ?? 0) + 1);
19	    }
20	  }
21	  return counts;
22	};
23	
24	const neighborPositions = function* (x: number, y: number): Generator<Cell> {
25	  for (let dx = -1; dx <= 1; dx++) {
26	    for (let dy = -1; dy <= 1; dy++) {
27	      if (dx === 0 && dy === 0) continue;
28	      yield [x + dx, y + dy];
29	    }
30	  }
31	};
32	
33	const survives = (neighborCount: number, isAlive: boolean): boolean =>
34	  neighborCount === NEIGHBORS_TO_BIRTH ||
35	  (neighborCount === NEIGHBORS_TO_SURVIVE && isAlive);
36	
37	export function nextGeneration(cells: Cell[]): Cell[] {
38	  const alive = new Set(cells.map(([x, y]) => cellKey(x, y)));
39	  const neighborCounts = countLiveNeighbors(cells);
40	
41	  const next: Cell[] = [];
42	  for (const [k, count] of neighborCounts) {
43	    if (survives(count, alive.has(k))) {
44	      next.push(parseCellKey(k));
45	    }
46	  }
47	  return next;
48	}
